const globalVar = 'I am global'; // global scope

function greet() {
  const funcVar = 'I am function-scoped'; // function scope
  console.log(globalVar); // ✅ can see global
  console.log(funcVar);   // ✅
}

if (true) {
  let blockVar = 'I am block-scoped';
  console.log(blockVar); // ✅
}
